// ==================== WS-Security Timestamp Token ====================

class TimestampToken {
    private Date created;
    private Date expires;
    private String messageId;

    public TimestampToken(Date created, Date expires, String messageId) {
        this.created = created;
        this.expires = expires;
        this.messageId = messageId;
    }

    public Date getCreated() { return created; }
    public Date getExpires() { return expires; }
    public String getMessageId() { return messageId; }

    public boolean isExpired() {
        return new Date().after(expires);
    }

    @Override
    public String toString() {
        return "TimestampToken{created=" + created + ", expires=" + expires +
               ", messageId=" + messageId + "}";
    }
}

// ==================== Replay Attack Detection Cache ====================

class ReplayDetectionCache {
    private static final ReplayDetectionCache INSTANCE = new ReplayDetectionCache();
    private final ConcurrentHashMap<String, Long> messageCache = new ConcurrentHashMap<>();
    private static final long CACHE_EXPIRY_MS = 5 * 60 * 1000; // 5 minutes

    private ReplayDetectionCache() {
        Timer cleanupTimer = new Timer(true);
        cleanupTimer.scheduleAtFixedRate(new TimerTask() {
            @Override
            public void run() {
                cleanExpiredEntries();
            }
        }, CACHE_EXPIRY_MS, CACHE_EXPIRY_MS);
    }

    public static ReplayDetectionCache getInstance() {
        return INSTANCE;
    }

    public boolean isReplay(String messageId) {
        if (messageId == null || messageId.isEmpty()) {
            return true;
        }
        Long previous = messageCache.putIfAbsent(messageId, System.currentTimeMillis());
        return previous != null;
    }

    public void recordMessage(String messageId) {
        messageCache.put(messageId, System.currentTimeMillis());
    }

    private void cleanExpiredEntries() {
        long now = System.currentTimeMillis();
        messageCache.entrySet().removeIf(entry -> (now - entry.getValue()) > CACHE_EXPIRY_MS);
    }

    public int getCacheSize() {
        return messageCache.size();
    }
}

// ==================== SOAP Security Header Parser ====================

class SecurityHeaderParser {

    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final SimpleDateFormat ISO_FORMAT = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
    private static final SimpleDateFormat ISO_FORMAT_NO_MILLIS = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss'Z'");

    static {
        ISO_FORMAT.setTimeZone(TimeZone.getTimeZone("UTC"));
        ISO_FORMAT_NO_MILLIS.setTimeZone(TimeZone.getTimeZone("UTC"));
    }

    public static TimestampToken extractTimestamp(SOAPHeader header) throws SOAPException, ParseException {
        if (header == null) {
            throw new SOAPException("SOAP header is null - WS-Security header required");
        }

        // Find wsse:Security element
        Iterator<?> securityHeaders = header.getChildElements(
                new QName(WSSE_NS, "Security"));

        if (!securityHeaders.hasNext()) {
            throw new SOAPException("WS-Security header not found");
        }

        SOAPHeaderElement securityElement = (SOAPHeaderElement) securityHeaders.next();

        // Find wsu:Timestamp element
        NodeList timestampNodes = securityElement.getElementsByTagNameNS(WSU_NS, "Timestamp");
        if (timestampNodes.getLength() == 0) {
            throw new SOAPException("Timestamp element not found in WS-Security header");
        }

        Element timestampElement = (Element) timestampNodes.item(0);
        String timestampId = timestampElement.getAttributeNS(WSU_NS, "Id");
        if (timestampId == null || timestampId.isEmpty()) {
            timestampId = timestampElement.getAttribute("wsu:Id");
        }

        // Extract Created
        NodeList createdNodes = timestampElement.getElementsByTagNameNS(WSU_NS, "Created");
        if (createdNodes.getLength() == 0) {
            throw new SOAPException("Created element not found in Timestamp");
        }
        String createdStr = createdNodes.item(0).getTextContent().trim();
        Date created = parseDate(createdStr);

        // Extract Expires
        NodeList expiresNodes = timestampElement.getElementsByTagNameNS(WSU_NS, "Expires");
        if (expiresNodes.getLength() == 0) {
            throw new SOAPException("Expires element not found in Timestamp");
        }
        String expiresStr = expiresNodes.item(0).getTextContent().trim();
        Date expires = parseDate(expiresStr);

        // Extract MessageID if present
        String messageId = null;
        NodeList messageIdNodes = timestampElement.getElementsByTagNameNS(WSU_NS, "MessageId");
        if (messageIdNodes.getLength() > 0) {
            messageId = messageIdNodes.item(0).getTextContent().trim();
        }
        if (messageId == null || messageId.isEmpty()) {
            messageId = timestampId;
        }
        if (messageId == null || messageId.isEmpty()) {
            messageId = UUID.randomUUID().toString();
        }

        return new TimestampToken(created, expires, messageId);
    }

    private static Date parseDate(String dateStr) throws ParseException {
        try {
            return ISO_FORMAT.parse(dateStr);
        } catch (ParseException e) {
            return ISO_FORMAT_NO_MILLIS.parse(dateStr);
        }
    }

    public static void validateTimestamp(TimestampToken token, long clockSkewMs) throws SOAPException {
        Date now = new Date();
        long clockSkew = clockSkewMs > 0 ? clockSkewMs : 300000; // default 5 min skew

        // Check if message is expired
        Date expiresWithSkew = new Date(token.getExpires().getTime() + clockSkew);
        if (now.after(expiresWithSkew)) {
            throw new SOAPException("WS-Security timestamp has expired. Expires: " +
                    token.getExpires() + ", Current time: " + now);
        }

        // Check if created time is not too far in the future
        Date createdWithSkew = new Date(token.getCreated().getTime() - clockSkew);
        if (now.before(createdWithSkew)) {
            throw new SOAPException("WS-Security timestamp created time is in the future. Created: " +
                    token.getCreated() + ", Current time: " + now);
        }

        // Check for replay
        ReplayDetectionCache cache = ReplayDetectionCache.getInstance();
        if (cache.isReplay(token.getMessageId())) {
            throw new SOAPException("Replay attack detected! Message ID: " + token.getMessageId() +
                    " has already been processed.");
        }
    }
}

